   303→
   304→    @Override
   305→    public MemoryRecords slice(int position, int size) {
   306→        if (position < 0)
   307→            throw new IllegalArgumentException("Invalid position: " + position + " in read from " + this);
   308→        if (position > buffer.limit())
   309→            throw new IllegalArgumentException("Slice from position " + position + " exceeds end position of " + this);
   310→        if (size < 0)
   311→            throw new IllegalArgumentException("Invalid size: " + size + " in read from " + this);
   312→
   313→        int availableBytes = Math.min(size, buffer.limit() - position);
   314→        // As of now, clients module support Java11 hence can't use ByteBuffer::slice(position, size) method.
   315→        // So we need to create a duplicate buffer and set the position and limit. Duplicate buffer
   316→        // is backed by original bytes hence not the content but only the relative position and limit
   317→        // are changed in the duplicate buffer. Once the position and limit are set, we can call the
   318→        // slice method to get the sliced buffer, which is a backed by the original buffer with the
   319→        // position reset to 0 and limit set to the size of the slice.
   320→        ByteBuffer slicedBuffer = buffer.duplicate();
   321→        slicedBuffer.position(position);
   322→        slicedBuffer.limit(position + availableBytes);
   323→        // Reset the position to 0 so that the sliced view has a relative position.
   324→        slicedBuffer = slicedBuffer.slice();
   325→
   326→        return readableRecords(slicedBuffer);
   327→    }
