/**
 * An immutable, in-memory {@link Records} implementation backed by a single {@link java.nio.ByteBuffer}
 * containing one or more serialized {@link RecordBatch record batches}.
 *
 * <p>{@code MemoryRecords} is the primary carrier of record data in the Kafka client stack. It is
 * used on the producer side (after {@link MemoryRecordsBuilder} closes a batch), on the broker
 * side (while replicating and compacting data), and on the consumer side (when deserializing fetch
 * responses). The class provides:
 * <ul>
 *   <li>Zero-copy serialization to a {@link java.nio.channels.GatheringByteChannel} via
 *       {@link #writeTo(org.apache.kafka.common.network.TransferableChannel, int, int)}.</li>
 *   <li>Lazy, streaming iteration over {@link MutableRecordBatch} instances through
 *       {@link #batches()} — no decompression occurs until individual records are requested.</li>
 *   <li>In-place record filtering and log compaction support through
 *       {@link #filterTo(RecordFilter, ByteBuffer, org.apache.kafka.common.utils.BufferSupplier)}.</li>
 *   <li>A family of static factory methods ({@code readableRecords}, {@code withRecords},
 *       {@code withTransactionalRecords}, etc.) covering common creation patterns.</li>
 * </ul>
 *
 * <p>To build a new {@code MemoryRecords} instance from scratch (i.e. when appending records),
 * use {@link MemoryRecordsBuilder} directly or via the
 * {@link #builder(ByteBuffer, byte, Compression, TimestampType, long)} family of overloads.
 * To wrap an existing serialized buffer for reading, use {@link #readableRecords(ByteBuffer)}.
 *
 * <h2>Thread safety</h2>
 * {@code MemoryRecords} is <em>not thread-safe</em>. The backing {@link java.nio.ByteBuffer} is
 * shared and its state (limit, position via duplicates) must not be modified concurrently from
 * multiple threads. Read-only access from multiple threads is safe as long as callers do not
 * mutate the buffer returned by {@link #buffer()}.
 *
 * @see RecordBatch
 * @see DefaultRecordBatch
 * @see MemoryRecordsBuilder
 * @see Records
 */
public class MemoryRecords extends AbstractRecords {
    public static final MemoryRecords EMPTY = MemoryRecords.readableRecords(ByteBuffer.allocate(0));

    private final ByteBuffer buffer;

    private final Iterable<MutableRecordBatch> batches = this::batchIterator;

    private int validBytes = -1;

    // Construct a writable memory records
    private MemoryRecords(ByteBuffer buffer) {
        Objects.requireNonNull(buffer, "buffer should not be null");
        this.buffer = buffer;
    }

    /**
     * Return the total number of bytes in the backing buffer, including any partial trailing batch.
     *
     * <p>This value is fixed at construction time and reflects the {@link java.nio.ByteBuffer#limit()}
     * of the underlying buffer. To obtain only the bytes belonging to complete, valid batches use
     * {@link #validBytes()}.
     *
     * @return total byte capacity of the backing buffer
     */
    @Override
    public int sizeInBytes() {
        return buffer.limit();
    }

    /**
     * Write a slice of this record set to the given channel without copying the underlying buffer.
     *
     * <p>Only the bytes in the range {@code [position, position + length)} are written. This range
     * may span partial batches; no validation of batch boundaries is performed.
     *
     * @param channel  the destination channel; must not be {@code null}
     * @param position byte offset within this record set from which to start writing; must be &ge; 0
     * @param length   number of bytes to write; must be &ge; 0
     * @return the number of bytes actually written, which may be less than {@code length} if the
     *         channel is non-blocking and its send buffer is full
     * @throws IOException              if an I/O error occurs while writing to the channel
     * @throws IllegalArgumentException if {@code position + length} exceeds {@link #sizeInBytes()}
     */
    @Override
    public int writeTo(TransferableChannel channel, int position, int length) throws IOException {
        if (((long) position) + length > buffer.limit())
            throw new IllegalArgumentException("position+length should not be greater than buffer.limit(), position: "
                    + position + ", length: " + length + ", buffer.limit(): " + buffer.limit());

        return Utils.tryWriteTo(channel, position, length, buffer);
    }

    /**
     * Write all records to the given channel (including partial records).
     * @param channel The channel to write to
     * @return The number of bytes written
     * @throws IOException For any IO errors writing to the channel
     */
    public int writeFullyTo(GatheringByteChannel channel) throws IOException {
        buffer.mark();
        int written = 0;
        while (written < sizeInBytes())
            written += channel.write(buffer);
        buffer.reset();
        return written;
    }

    /**
     * The total number of bytes in this message set not including any partial, trailing messages. This
     * may be smaller than what is returned by {@link #sizeInBytes()}.
     * @return The number of valid bytes
     */
    public int validBytes() {
        if (validBytes >= 0)
            return validBytes;

        int bytes = 0;
        for (RecordBatch batch : batches())
            bytes += batch.sizeInBytes();

        this.validBytes = bytes;
        return bytes;
